"use client"

import { useUnlockWallet } from "./use-unlock-wallet"
import { UnlockWalletUi } from "./unlock-wallet-ui"
import type { UnlockPlatform, UnlockWalletResult } from "./use-unlock-wallet"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export { useUnlockWallet } from "./use-unlock-wallet"
export { UnlockWalletUi } from "./unlock-wallet-ui"
export type {
  UnlockPlatform,
  UnlockWalletResult,
  UseUnlockWalletOptions,
  UseUnlockWalletReturn,
} from "./use-unlock-wallet"
export type { UnlockWalletUiProps } from "./unlock-wallet-ui"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Props for the composed UnlockWallet block */
export interface UnlockWalletProps {
  /** Platform determines which unlock methods are available (default: "other") */
  platform?: UnlockPlatform
  /** Application name displayed in the unlock UI (default: "Wallet") */
  appName?: string
  /** Callback to execute the unlock attempt */
  onUnlock?: (passphrase?: string) => Promise<UnlockWalletResult>
  /** Called on successful unlock */
  onSuccess?: () => void
  /** Called on error */
  onError?: (error: Error) => void
  /** Optional CSS class */
  className?: string
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

/**
 * Full Unlock Wallet block: passphrase or biometric unlock screen.
 *
 * On macOS, presents a Touch ID button first with a passphrase fallback.
 * On other platforms, presents a passphrase input directly.
 *
 * The `onUnlock` callback receives an optional passphrase string
 * (undefined for biometric) and should return `{ success, error? }`.
 *
 * @example
 * ```tsx
 * import { UnlockWallet } from "@/components/blocks/unlock-wallet"
 *
 * <UnlockWallet
 *   platform="macos"
 *   appName="My Wallet"
 *   onUnlock={async (passphrase) => {
 *     if (passphrase) {
 *       return verifyPassphrase(passphrase)
 *     }
 *     return attemptBiometric()
 *   }}
 * />
 * ```
 */
export function UnlockWallet({
  platform = "other",
  appName = "Wallet",
  onUnlock,
  onSuccess,
  onError,
  className,
}: UnlockWalletProps) {
  const { isLoading, error, isUnlocked, failedAttempts, execute, reset } =
    useUnlockWallet({
      platform,
      appName,
      onUnlock,
      onSuccess,
      onError,
    })

  return (
    <UnlockWalletUi
      platform={platform}
      appName={appName}
      isLoading={isLoading}
      error={error}
      isUnlocked={isUnlocked}
      failedAttempts={failedAttempts}
      onSubmit={execute}
      onReset={reset}
      className={className}
    />
  )
}

"use client"

import { useCallback, useState } from "react"
import {
  AlertCircle,
  CheckCircle2,
  Fingerprint,
  KeyRound,
  Loader2,
  Lock,
  ShieldCheck,
} from "lucide-react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { cn } from "@/lib/utils"
import type { UnlockPlatform, UnlockWalletResult } from "./use-unlock-wallet"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface UnlockWalletUiProps {
  /** Platform determines which unlock methods are shown */
  platform: UnlockPlatform
  /** Application name displayed in the UI */
  appName: string
  /** Whether an unlock is in progress */
  isLoading: boolean
  /** Current error state */
  error: Error | null
  /** Whether the wallet is already unlocked */
  isUnlocked: boolean
  /** Number of failed attempts */
  failedAttempts: number
  /** Called when the user attempts to unlock */
  onSubmit: (passphrase?: string) => Promise<UnlockWalletResult>
  /** Reset error state */
  onReset: () => void
  /** Optional CSS class */
  className?: string
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function UnlockWalletUi({
  platform,
  appName,
  isLoading,
  error,
  isUnlocked,
  failedAttempts,
  onSubmit,
  onReset,
  className,
}: UnlockWalletUiProps) {
  const [passphrase, setPassphrase] = useState("")
  const [showPassphrase, setShowPassphrase] = useState(false)

  const isMac = platform === "macos"

  const handleBiometricUnlock = useCallback(async () => {
    await onSubmit(undefined)
  }, [onSubmit])

  const handlePassphraseUnlock = useCallback(async () => {
    if (!passphrase.trim()) return
    await onSubmit(passphrase)
    setPassphrase("")
  }, [onSubmit, passphrase])

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === "Enter") {
        e.preventDefault()
        void handlePassphraseUnlock()
      }
    },
    [handlePassphraseUnlock],
  )

  const handleShowPassphrase = useCallback(() => {
    setShowPassphrase(true)
    onReset()
  }, [onReset])

  // Unlocked state
  if (isUnlocked) {
    return (
      <Card className={cn("w-full max-w-sm", className)}>
        <CardContent className="flex flex-col items-center gap-4 pt-6">
          <div className="flex size-16 items-center justify-center rounded-full bg-primary/10">
            <ShieldCheck className="size-8 text-primary" aria-hidden="true" />
          </div>
          <div className="flex flex-col items-center gap-1 text-center">
            <p className="text-lg font-semibold">Wallet Unlocked</p>
            <p className="text-sm text-muted-foreground">
              {appName} is ready to use
            </p>
          </div>
          <Badge variant="outline" className="gap-1.5">
            <CheckCircle2 className="size-3" aria-hidden="true" />
            Authenticated
          </Badge>
        </CardContent>
      </Card>
    )
  }

  // macOS biometric-first layout
  if (isMac && !showPassphrase) {
    return (
      <Card className={cn("w-full max-w-sm", className)}>
        <CardHeader className="items-center text-center">
          <div className="mb-2 flex size-16 items-center justify-center rounded-full bg-muted">
            <Lock className="size-8 text-muted-foreground" aria-hidden="true" />
          </div>
          <CardTitle>{appName}</CardTitle>
          <CardDescription>
            Use Touch ID to unlock your wallet
          </CardDescription>
        </CardHeader>

        <CardContent className="flex flex-col items-center gap-4">
          <Button
            size="lg"
            className="w-full gap-2"
            onClick={() => { void handleBiometricUnlock() }}
            disabled={isLoading}
            aria-busy={isLoading}
          >
            {isLoading ? (
              <>
                <Loader2
                  className="animate-spin"
                  data-icon="inline-start"
                  aria-hidden="true"
                />
                Authenticating...
              </>
            ) : (
              <>
                <Fingerprint data-icon="inline-start" aria-hidden="true" />
                Unlock with Touch ID
              </>
            )}
          </Button>

          {/* Error */}
          {error && (
            <div className="flex w-full items-start gap-3 rounded-md border border-destructive/20 bg-destructive/5 p-3">
              <AlertCircle className="mt-0.5 size-4 flex-shrink-0 text-destructive" />
              <div className="flex flex-col gap-1">
                <p className="text-sm font-medium">Unlock failed</p>
                <p className="text-xs text-muted-foreground">
                  {error.message}
                </p>
              </div>
            </div>
          )}

          {failedAttempts > 0 && (
            <Badge variant="secondary" className="text-xs">
              {failedAttempts} failed {failedAttempts === 1 ? "attempt" : "attempts"}
            </Badge>
          )}
        </CardContent>

        <CardFooter className="justify-center">
          <Button
            variant="link"
            size="sm"
            className="text-xs text-muted-foreground"
            onClick={handleShowPassphrase}
          >
            Use passphrase instead
          </Button>
        </CardFooter>
      </Card>
    )
  }

  // Passphrase layout (default for "other" or fallback from macOS)
  return (
    <Card className={cn("w-full max-w-sm", className)}>
      <CardHeader className="items-center text-center">
        <div className="mb-2 flex size-16 items-center justify-center rounded-full bg-muted">
          <Lock className="size-8 text-muted-foreground" aria-hidden="true" />
        </div>
        <CardTitle>{appName}</CardTitle>
        <CardDescription>
          Enter your passphrase to unlock your wallet
        </CardDescription>
      </CardHeader>

      <CardContent className="flex flex-col gap-4">
        <div className="flex flex-col gap-2">
          <Label htmlFor="unlock-passphrase">Passphrase</Label>
          <Input
            id="unlock-passphrase"
            type="password"
            placeholder="Enter your passphrase"
            value={passphrase}
            onChange={(e) => setPassphrase(e.target.value)}
            onKeyDown={handleKeyDown}
            disabled={isLoading}
            autoComplete="current-password"
            autoFocus
          />
        </div>

        {/* Error */}
        {error && (
          <div className="flex items-start gap-3 rounded-md border border-destructive/20 bg-destructive/5 p-3">
            <AlertCircle className="mt-0.5 size-4 flex-shrink-0 text-destructive" />
            <div className="flex flex-col gap-1">
              <p className="text-sm font-medium">Unlock failed</p>
              <p className="text-xs text-muted-foreground">{error.message}</p>
            </div>
          </div>
        )}

        {failedAttempts > 0 && (
          <div className="flex justify-center">
            <Badge variant="secondary" className="text-xs">
              {failedAttempts} failed {failedAttempts === 1 ? "attempt" : "attempts"}
            </Badge>
          </div>
        )}
      </CardContent>

      <CardFooter className="flex flex-col gap-2">
        <Button
          className="w-full gap-2"
          onClick={() => { void handlePassphraseUnlock() }}
          disabled={isLoading || !passphrase.trim()}
          aria-busy={isLoading}
        >
          {isLoading ? (
            <>
              <Loader2
                className="animate-spin"
                data-icon="inline-start"
                aria-hidden="true"
              />
              Unlocking...
            </>
          ) : (
            <>
              <KeyRound data-icon="inline-start" aria-hidden="true" />
              Unlock Wallet
            </>
          )}
        </Button>

        {isMac && (
          <Button
            variant="link"
            size="sm"
            className="text-xs text-muted-foreground"
            onClick={() => {
              setShowPassphrase(false)
              onReset()
            }}
          >
            Use Touch ID instead
          </Button>
        )}
      </CardFooter>
    </Card>
  )
}

import { useCallback, useState } from "react"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Supported platform values */
export type UnlockPlatform = "macos" | "other"

/** Result returned from the onUnlock callback */
export interface UnlockWalletResult {
  /** Whether the unlock was successful */
  success: boolean
  /** Error message on failure */
  error?: string
}

/** Options for the useUnlockWallet hook */
export interface UseUnlockWalletOptions {
  /** Platform determines which unlock methods are available */
  platform?: UnlockPlatform
  /** Application name displayed in the unlock UI */
  appName?: string
  /** Callback to execute the actual unlock */
  onUnlock?: (passphrase?: string) => Promise<UnlockWalletResult>
  /** Called on successful unlock */
  onSuccess?: () => void
  /** Called on error */
  onError?: (error: Error) => void
}

/** Return type of useUnlockWallet hook */
export interface UseUnlockWalletReturn {
  /** Whether an unlock operation is in progress */
  isLoading: boolean
  /** Current error, if any */
  error: Error | null
  /** Whether the wallet has been unlocked */
  isUnlocked: boolean
  /** Number of failed attempts */
  failedAttempts: number
  /** Execute an unlock attempt */
  execute: (passphrase?: string) => Promise<UnlockWalletResult>
  /** Reset error state */
  reset: () => void
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useUnlockWallet({
  onUnlock,
  onSuccess,
  onError,
}: UseUnlockWalletOptions = {}): UseUnlockWalletReturn {
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<Error | null>(null)
  const [isUnlocked, setIsUnlocked] = useState(false)
  const [failedAttempts, setFailedAttempts] = useState(0)

  const execute = useCallback(
    async (passphrase?: string): Promise<UnlockWalletResult> => {
      if (!onUnlock) {
        const err = new Error("onUnlock callback is required")
        setError(err)
        onError?.(err)
        return { success: false, error: err.message }
      }

      setIsLoading(true)
      setError(null)

      try {
        const result = await onUnlock(passphrase)

        if (!result.success) {
          const errMsg = result.error ?? "Unlock failed"
          const err = new Error(errMsg)
          setError(err)
          setFailedAttempts((prev) => prev + 1)
          onError?.(err)
          return result
        }

        setIsUnlocked(true)
        setFailedAttempts(0)
        onSuccess?.()
        return result
      } catch (err) {
        const e = err instanceof Error ? err : new Error(String(err))
        setError(e)
        setFailedAttempts((prev) => prev + 1)
        onError?.(e)
        return { success: false, error: e.message }
      } finally {
        setIsLoading(false)
      }
    },
    [onUnlock, onSuccess, onError],
  )

  const reset = useCallback(() => {
    setError(null)
  }, [])

  return { isLoading, error, isUnlocked, failedAttempts, execute, reset }
}
